CREATE OR REPLACE FUNCTION pg_temp.count_estimate(
    query text
) RETURNS integer LANGUAGE plpgsql AS $$
DECLARE
    plan jsonb;
BEGIN
    EXECUTE 'EXPLAIN (FORMAT JSON)' || query INTO plan;
    RETURN plan->0->'Plan'->'Plan Rows';
END;
$$

do $func$
begin
  if not exists (
    select 1
    from pg_roles
    where rolname = 'cli_login_postgres'
  )
  then
    create role cli_login_postgres noinherit login noreplication;
  end if;
  grant postgres to cli_login_postgres;
  set role postgres;
  execute format(
    $$alter role cli_login_postgres with password 'JFQLdimSuEOoZjiiZsgjDFDgwMLgQRQW' valid until %L$$,
    now() + interval '300 second'
  );
end
$func$ language plpgsql
